SELECT S.GENERO FROM LATTES_ORIENTACAO O JOIN SERVIDOR S ON S.PK_SIAPE = O.FK_SIAPE WHERE (LOWER(O.TIPO) LIKE '%inicia%cientif%' OR LOWER(O.TIPO) LIKE '%inicia%tecnolog%') AND S.SIGLA_CAMPUS = 'GYN' AND LOWER(COALESCE(S.AREA_INGRESSO, S.AREA_INGRESSO_OG)) LIKE '%matem%' AND O.ANO BETWEEN (CAST(strftime('%Y', 'now') AS INTEGER) - 4) AND CAST(strftime('%Y', 'now') AS INTEGER) GROUP BY S.GENERO ORDER BY COUNT(*) DESC LIMIT 1